text:
{
  "formal_minutes": {
    "project_code": "PUBLIC_MEETING_SMOKE",
    "meeting_title": "UI Theme Package Release Readiness",
    "confirmed_decisions": [
      {
        "item": "공개 릴리스 목표 시점은 금요일 15:00 KST로 정했다.",
        "condition": "smoke test가 통과해야 한다."
      },
      {
        "item": "packageName mismatch가 발생하면 먼저 패키지 설정을 확인한다.",
        "condition": "스크립트는 계약 자체가 잘못된 경우에만 검토한다."
      },
      {
        "item": "Minjun은 금요일 10:00 KST까지 smoke test를 다시 실행하고 결과를 공유한다."
      },
      {
        "item": "Doyun은 금요일 12:00 KST까지 failure triage note를 action_items.md에 작성한다."
      },
      {
        "item": "Hara는 Minjun이 smoke 결과를 올린 뒤 생성된 tarball 경로를 확인한다."
      }
    ],
    "rejected_proposals": [
      {
        "item": "Hara가 제안한 'smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경' 안은 거절되었다."
      },
      {
        "item": "Seoyeon의 수요일 릴리스 제안은 최종 결정으로 채택되지 않았다."
      }
    ],
    "internal_stretch_goals": [
      {
        "item": "수요일 릴리스는 내부 stretch goal로만 남았다."
      },
      {
        "item": "README install steps는 가능하면 목요일까지 검토하자는 제안이 나왔지만, 공식 작업 배정은 되지 않았다."
      }
    ],
    "risks": [
      {
        "item": "tarball 경로가 잘못되면 릴리스가 지연될 수 있다."
      },
      {
        "item": "README install steps가 오래되었으면 릴리스 노트가 사용자에게 잘못된 정보를 줄 수 있다."
      }
    ],
    "open_questions": [
      {
        "item": "최종 릴리스 승인 권한이 누구에게 있는지 확정되지 않았다."
      },
      {
        "item": "릴리스 노트에 내부 수요일 stretch goal을 언급할지 결정되지 않았다."
      }
    ],
    "non_decisions": [
      {
        "item": "고객명은 언급되지 않았다."
      },
      {
        "item": "예산 정보는 언급되지 않았다."
      },
      {
        "item": "보안 사고는 언급되지 않았다."
      },
      {
        "item": "프로덕션 장애는 언급되지 않았다."
      },
      {
        "item": "법무 승인 요구사항은 언급되지 않았다."
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "smoke test를 다시 실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "confirmed",
      "source_certainty": "explicitly stated"
    },
    {
      "owner": "Doyun",
      "task": "failure triage note를 action_items.md에 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "confirmed",
      "source_certainty": "explicitly stated"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 smoke 결과가 올라온 뒤 생성된 tarball 경로를 확인한다.",
      "due": "미정",
      "status": "confirmed",
      "source_certainty": "explicitly stated"
    }
  ],
  "followup_note": "다음 확인 대상은 smoke test 결과, tarball 경로, README install steps의 실제 상태, 그리고 최종 릴리스 승인권자다. 수요일 릴리스, 고객명, 예산, 보안, 장애, 법무 승인, 또는 소유자/기한이 정해지지 않은 항목은 임의로 채워 넣지 말아야 한다.",
  "non_invention_rules": [
    "고객명은 만들지 않는다.",
    "예산은 만들지 않는다.",
    "보안 사고는 만들지 않는다.",
    "프로덕션 장애는 만들지 않는다.",
    "법무 승인 요구사항은 만들지 않는다.",
    "소유자가 명시되지 않은 작업에 소유자를 임의 지정하지 않는다.",
    "기한이 명시되지 않은 작업에 임의 마감일을 부여하지 않는다.",
    "확정되지 않은 승인권자나 의사결정자를 임의로 지정하지 않는다.",
    "합의되지 않은 제안은 확정 결정처럼 쓰지 않는다."
  ]
}
